/* ═══════════════════════════════════════════
   SIHYEON PLAY OS - 꼬마 고양이 돌보기 (Cat Care)
   - 대상: 4살 시현이 (터치 전용, 드래그 없음)
   - 특징: 캐릭터 선택, 4단계 순차 돌보기, 화려한 피드백
   - 파일: js/games/cat-care.js
═══════════════════════════════════════════ */

(function () {
  const GAME_KEY = 'catCare';
  const STYLE_ID = 'sihyeon-cat-care-style';

  // [중요] 아빠! 나중에 이미지를 assets/games/cat-care/ 폴더에 넣고 이름을 아래와 맞춰주세요.
  const CAT_DATA = {
    white: {
      id: 'white',
      name: '흰 고양이',
      color: '#FFB74D', // 버튼 포인트 색상
      selectImg: 'assets/games/cat-care/white_select.jpg',
      steps: {
        default: 'assets/games/cat-care/white_default.jpg',
        eat:     'assets/games/cat-care/white_eat.jpg',
        bath:    'assets/games/cat-care/white_bath.jpg',
        sleep:   'assets/games/cat-care/white_sleep.jpg'
      }
    },
    gray: {
      id: 'gray',
      name: '회색 고양이',
      color: '#64B5F6',
      selectImg: 'assets/games/cat-care/gray_select.jpg',
      steps: {
        default: 'assets/games/cat-care/gray_default.jpg',
        eat:     'assets/games/cat-care/gray_eat.jpg',
        bath:    'assets/games/cat-care/gray_bath.jpg',
        sleep:   'assets/games/cat-care/gray_sleep.jpg'
      }
    }
  };

  const state = {
    container: null,
    options: {},
    currentCat: null,
    step: 'select', // select -> feed -> bath -> pet -> sleep -> finish
    destroyed: false
  };

  // ─── CSS 스타일 주입 ───
  function injectStyle() {
    if (document.getElementById(STYLE_ID)) return;
    const style = document.createElement('style');
    style.id = STYLE_ID;
    style.innerHTML = `
      .cc-root {
        position: relative; width: 100%; height: 100%;
        display: flex; flex-direction: column; align-items: center; justify-content: center;
        background: linear-gradient(135deg, #fff9c4 0%, #ffecb3 100%);
        overflow: hidden; font-family: 'Jua', sans-serif;
        transition: background 1s ease;
      }
      .cc-night { background: linear-gradient(135deg, #1a237e 0%, #000051 100%) !important; }

      /* 캐릭터 선택 화면 */
      .cc-select-box { display: flex; gap: 30px; animation: ccPopIn 0.6s cubic-bezier(0.17, 0.67, 0.83, 0.67); }
      .cc-cat-card {
        width: clamp(140px, 40vw, 250px); cursor: pointer;
        background: white; padding: 15px; border-radius: 40px;
        box-shadow: 0 15px 30px rgba(0,0,0,0.1); transition: transform 0.2s;
      }
      .cc-cat-card:active { transform: scale(0.9); }
      .cc-cat-card img { width: 100%; border-radius: 30px; }
      .cc-cat-card p { font-size: 24px; margin-top: 15px; color: #333; text-align: center; }

      /* 게임 스테이지 메인 고양이 */
      .cc-main-display {
        flex: 1; display: flex; align-items: center; justify-content: center;
        width: 100%; position: relative;
      }
      .cc-cat-img {
        width: clamp(280px, 70vw, 450px); border-radius: 50px;
        box-shadow: 0 20px 40px rgba(0,0,0,0.2);
        border: 10px solid white; transition: all 0.5s;
        animation: ccFloat 3s ease-in-out infinite;
      }
      .cc-bounce { animation: ccBounce 0.5s cubic-bezier(0.36, 0, 0.66, -0.56) !important; }

      @keyframes ccFloat { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-15px)} }
      @keyframes ccBounce { 0%,100%{transform:scale(1)} 50%{transform:scale(1.2)} }
      @keyframes ccPopIn { from{transform:scale(0);opacity:0} to{transform:scale(1);opacity:1} }

      /* 하단 액션 버튼 */
      .cc-action-bar {
        height: 180px; width: 100%; display: flex; align-items: center; justify-content: center;
        padding-bottom: 20px;
      }
      .cc-btn {
        min-width: 130px; min-height: 130px; border-radius: 50%;
        border: 6px solid white; font-size: 50px; cursor: pointer;
        box-shadow: 0 10px 0 rgba(0,0,0,0.1); display: grid; place-items: center;
        transition: transform 0.1s; animation: ccPopIn 0.5s;
      }
      .cc-btn:active { transform: translateY(8px); box-shadow: 0 2px 0 rgba(0,0,0,0.1); }
      
      /* 파티클 효과 */
      .cc-particle {
        position: absolute; pointer-events: none; z-index: 50;
        animation: ccExplode 0.8s ease-out forwards;
      }
      @keyframes ccExplode {
        0%{transform:translate(0,0) scale(1); opacity:1}
        100%{transform:translate(var(--tx),var(--ty)) scale(0); opacity:0}
      }
    `;
    document.head.appendChild(style);
  }

  // ─── 음성 & 사운드 ───
  function speak(text) {
    if (typeof speechSynthesis !== 'undefined') {
      speechSynthesis.cancel();
      const msg = new SpeechSynthesisUtterance(text);
      msg.lang = 'ko-KR';
      msg.rate = 0.9;
      speechSynthesis.speak(msg);
    }
  }

  // ─── 화려한 파티클 폭발 ───
  function burst(x, y, color = '#FFEB3B', count = 20, emoji = '') {
    for (let i = 0; i < count; i++) {
      const p = document.createElement('div');
      p.className = 'cc-particle';
      const angle = Math.random() * Math.PI * 2;
      const dist = 100 + Math.random() * 150;
      p.style.setProperty('--tx', `${Math.cos(angle) * dist}px`);
      p.style.setProperty('--ty', `${Math.sin(angle) * dist}px`);
      p.style.left = `${x}px`; p.style.top = `${y}px`;
      
      if (emoji) {
        p.innerText = emoji;
        p.style.fontSize = '30px';
      } else {
        p.style.width = '15px'; p.style.height = '15px';
        p.style.borderRadius = '50%';
        p.style.backgroundColor = color;
      }
      state.container.querySelector('.cc-root').appendChild(p);
      setTimeout(() => p.remove(), 800);
    }
  }

  // ─── 메인 렌더링 함수 ───
  function renderScene() {
    if (state.destroyed) return;
    const root = state.container.querySelector('.cc-root');
    root.innerHTML = '';

    // 1. 캐릭터 선택 화면
    if (state.step === 'select') {
      root.classList.remove('cc-night');
      const box = document.createElement('div');
      box.className = 'cc-select-box';
      
      Object.values(CAT_DATA).forEach(cat => {
        const card = document.createElement('div');
        card.className = 'cc-cat-card';
        card.innerHTML = `<img src="${cat.selectImg}" onerror="this.src='https://api.iconify.design/twemoji:crying-cat.svg'"><p>${cat.name}</p>`;
        card.onclick = () => selectCat(cat);
        box.appendChild(card);
      });
      root.appendChild(box);
      speak("시현아, 어떤 야옹이를 돌봐줄까?");
      return;
    }

    // 2. 돌보기 스테이지 (Feed, Bath, Pet, Sleep)
    const cat = state.currentCat;
    const sceneHTML = `
      <div class="cc-main-display">
        <img id="cat-main" class="cc-cat-img" src="${cat.steps[getStepImgKey()] || cat.steps.default}">
      </div>
      <div class="cc-action-bar" id="action-bar"></div>
    `;
    root.innerHTML = sceneHTML;

    const bar = root.querySelector('#action-bar');
    const catImg = root.querySelector('#cat-main');

    if (state.step === 'feed') {
      createBtn(bar, '🐟', cat.color, () => handleFeed(catImg));
      speak("야옹이가 배고프대! 맛있는 물고기를 줄까?");
    } else if (state.step === 'bath') {
      createBtn(bar, '🫧', '#E1F5FE', () => handleBath(catImg));
      speak("보글보글 목욕하자!");
    } else if (state.step === 'pet') {
      speak("야옹이를 쓰다듬어줘!");
      catImg.style.cursor = 'pointer';
      catImg.onclick = (e) => handlePet(e, catImg);
    } else if (state.step === 'sleep') {
      root.classList.add('cc-night');
      createBtn(bar, '🛌', '#5C6BC0', () => handleSleep(catImg));
      speak("코오... 이제 자야 할 시간이야.");
    } else if (state.step === 'finish') {
      createBtn(bar, '🏠', '#4CAF50', () => state.options.closeToParkHome?.());
      speak("시현아, 정말 잘했어! 야옹이가 행복하대!");
      if (state.options.fireConfetti) state.options.fireConfetti();
    }
  }

  function getStepImgKey() {
    if (state.step === 'feed_ing') return 'eat';
    if (state.step === 'bath_ing') return 'bath';
    if (state.step === 'sleep_ing') return 'sleep';
    if (state.step === 'pet') return 'default';
    return 'default';
  }

  function createBtn(parent, emoji, color, onClick) {
    const btn = document.createElement('div');
    btn.className = 'cc-btn';
    btn.style.backgroundColor = color;
    btn.innerHTML = emoji;
    btn.onclick = (e) => {
      const rect = btn.getBoundingClientRect();
      burst(rect.left + rect.width / 2, rect.top + rect.height / 2, color);
      onClick();
    };
    parent.appendChild(btn);
  }

  // ─── 핸들러 함수들 ───
  function selectCat(cat) {
    state.currentCat = cat;
    state.step = 'feed';
    renderScene();
  }

  function handleFeed(img) {
    state.step = 'feed_ing';
    renderScene();
    speak("냠냠, 쩝쩝! 시현아 고마워!");
    burst(window.innerWidth / 2, window.innerHeight / 2, '#FF5252', 15, '❤️');
    setTimeout(() => { state.step = 'bath'; renderScene(); }, 2500);
  }

  function handleBath(img) {
    state.step = 'bath_ing';
    renderScene();
    speak("보글보글! 시원해 시현아!");
    burst(window.innerWidth / 2, window.innerHeight / 2, '#81D4FA', 20, '🫧');
    setTimeout(() => { state.step = 'pet'; renderScene(); }, 2500);
  }

  function handlePet(e, img) {
    img.classList.add('cc-bounce');
    speak("고릉고릉~ 기분 좋아!");
    burst(e.clientX, e.clientY, '#FF4081', 10, '💖');
    setTimeout(() => {
      img.classList.remove('cc-bounce');
      state.step = 'sleep';
      renderScene();
    }, 2000);
  }

  function handleSleep(img) {
    state.step = 'sleep_ing';
    renderScene();
    speak("코오... 시현아 잘 자~ 사랑해!");
    burst(window.innerWidth / 2, window.innerHeight / 2, '#FFD700', 10, '⭐');
    setTimeout(() => { state.step = 'finish'; renderScene(); }, 3000);
  }

  // ─── 라이프사이클 API ───
  function render(container, options = {}) {
    destroy();
    injectStyle();
    state.container = container;
    state.options = options;
    state.destroyed = false;
    state.step = 'select';
    state.currentCat = null;

    container.innerHTML = `<div class="cc-root"></div>`;
    renderScene();
  }

  function destroy() {
    state.destroyed = true;
    if (state.container) state.container.innerHTML = '';
    if (typeof speechSynthesis !== 'undefined') speechSynthesis.cancel();
  }

  window.SihyeonGames = window.SihyeonGames || {};
  window.SihyeonGames.catCare = { id: GAME_KEY, render, destroy };
})();
